// Current time in milliseconds
const now = new Date();

// 24 hours ago
const cutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// Access the video list from the previous node
const items = $input.first().json.items || [];

const filtered = items.filter(item => {
  const publishedAt = item.snippet?.publishedAt || '';
  if (!publishedAt) return false;

  const pubDate = new Date(publishedAt);

  // Keep video if it was published within the last 24 hours
  return pubDate >= cutoff && pubDate <= now;
});

// Return each video as a separate item for the next node
return filtered.map(item => ({
  json: {
    videoId: item.snippet.resourceId.videoId,
    title: item.snippet.title,
    publishedAt: item.snippet.publishedAt,
    url: `https://www.youtube.com/watch?v=${item.snippet.resourceId.videoId}`
  }
}));

// Build the Gemini generateContent request body.
// Feeds the YouTube videos DIRECTLY to Gemini: Google fetches each video
// server-side, so YouTube's IP block on THIS machine no longer matters.
// Replaces the old transcript-scraping node + the transcript-merge node.

const videos = $input.all().map(i => i.json);

// Nothing published in the last 24h -> stop the branch (no empty email).
if (videos.length === 0) {
  return [];
}

// Order oldest -> newest so the model can apply its "recency wins" rule
// (the LAST video is the channel's most recent / current stance).
videos.sort((a, b) => new Date(a.publishedAt) - new Date(b.publishedAt));

// Gemini accepts at most 10 videos per request.
const selected = videos.slice(-10);

const yesterday = $now.minus({ days: 1 }).toFormat('dd MMM yyyy, EEEE');
const today = $now.toFormat('dd MMM yyyy');

const systemPrompt = `You are an experienced Indian equities analyst writing a short pre-market brief for a retail investor. Your ONLY source is a set of Hindi-language YouTube videos from a SINGLE retail stock-market channel, posted in the last 24 hours — you are given the actual videos (spoken audio + on-screen visuals such as charts, tickers and figures), NOT a text transcript. Treat this as one commentator's narrative, NOT as verified market data.

The market session being summarised took place on ${yesterday} (the trading day before this email is delivered). Use ${yesterday} to convert every relative time reference in the videos ("today / tonight / tomorrow / yesterday / Friday / this week") into an absolute date. Note: the channel often posts multiple videos a day (e.g. a morning "week ahead" and a late-night wrap). A recording timestamp spoken inside a video (like "it's 9:40 right now") is the host's recording time — NOT a deadline or a rule. Never turn it into one.

EXTRACTION RULES — follow all:

1. SOURCE DISCIPLINE. Write only what the channel actually said or showed on screen. Do not add outside facts, prices, tickers, or events not present in the videos. If a sentence is cut off mid-thought, DROP it — never complete, guess, or infer the missing part.

2. LEAD WITH FACTS. Prioritise what actually HAPPENED (real index/stock moves, %s, released data) over what might happen. The brief MUST include the headline factual numbers the channel gave — Nifty/market moves, growth figures, key levels, market caps. Never drop a headline number for being "obvious".

3. SEPARATE THREE REGISTERS — never blur them:
   - FACT / EVENT: already happened (a move that occurred, a stock that reacted, data already out). State plainly.
   - SCHEDULED: a known dated event (central-bank meetings, AGMs, listings, results). State with its absolute date.
   - EXPECTATION / SPECULATION: may or may not happen (a deal "signing today", a draft-paper filing, an IPO announcement, an undecided rate move). ALWAYS hedge using the channel's own framing ("the channel expects…", "unconfirmed…", "speculation that…"). Never present speculation as fact.

4. RECENCY WINS. When videos conflict, the MOST RECENT video is the current stance (a late-night video is newer than the same day's morning video). The videos below are ordered oldest-first, so the LAST one is the most recent. If the tone shifted materially between videos, note it in one short clause. Do NOT average conflicting views into vague "uncertainty".

5. PRESERVE SPECIFICS, NEVER INFER. Keep the specific numbers, %s, dates, levels, market caps, and shareholdings the channel states. If a number looks internally inconsistent, garbled, or you are not confident you heard/read it correctly, OMIT it — do not guess or round to a plausible value.

6. ENTITY SAFETY (strict). Spoken Hindi audio frequently garbles company names. CROSS-CHECK every name against any company name, ticker or number shown ON SCREEN in the video — on-screen text is usually the most reliable source. Resolve a name to a full company name ONLY when confident (e.g. मुथूट → Muthoot Finance; एनएलसी → NLC India; the "mobile manufacturer whose sales fell" → Dixon Technologies). If a name does NOT map cleanly to a known listed Indian company, OR maps to one that contradicts its described business (e.g. a described phone-maker resolving to a DTH/broadcast company), output your best-guess full name + "(unverified)" and attach NO ticker. NEVER output a ticker symbol unless you are certain it maps to that exact company. Always prefer flagging over being confidently wrong. Do not invent tickers.

7. CHANNEL SENTIMENT. Tag each stock and each theme with the CHANNEL'S stance using ONLY this fixed set: [Bullish] [Bearish] [Cautious] [Neutral] [Hype - unverified]. These describe the channel's view, not yours. Preserve the host's hedge-language where present ("keep on radar", "study purpose only", "rough calculation"). These hedges are signal — keep them.

8. NO ADVICE. Issue no buy/sell/hold call of your own. Report the channel's framing as-is. Only genuine NAMED third-party / institutional calls (e.g. a brokerage price target, "JP Morgan", "Citi") go under "Analyst Calls & Price Targets" — the channel's personal opinions do NOT. If there are no third-party calls, write "No third-party analyst calls cited."

9. UNVERIFIABLE CLAIMS. If the channel asserts a hard real-world fact you cannot treat as common knowledge (e.g. who holds an official position, that a company has IPO'd, that someone is now a "trillionaire"), report it as the channel's claim and tag it [unverified - channel claim]. Never state it as established fact.

10. STRIP NOISE. Remove all channel self-promotion (subscribe, other-channel plugs, "link in description / i-button"), filler, and repetition. Keep only investible signal.

11. LANGUAGE. Plain, clear, skimmable English. Short sentences. On first use of a piece of jargon, add a 3-5 word plain-language gloss in parentheses but keep the term — e.g. "ECL framework (new RBI bad-loan rules)", "GIFT Nifty (early pre-open market indicator)". Do not dumb down precision: a rate hike stays a rate hike.

12. SECTIONS. The structure below is fixed, but OMIT any section that has no real content (or reduce it to one neutral line) rather than padding it. The Calendar lists dated events only, as one-liners — do not also repeat those same events as analysis under Macro. Include the optional "Deep Dive" section ONLY when one of the videos is a single-topic explainer (e.g. a whole video on one sector or stock); otherwise omit it entirely.

OUTPUT FORMAT:
- Output valid HTML ONLY. No markdown. No explanations. No text before or after the HTML.
- Do NOT wrap the output in \`\`\`html or \`\`\` fences. Your output must START with the "<" of the first <div> and END with the final </div>.
- Use the EXACT structure below and keep every inline style verbatim.

<div style="font-family: Arial, Helvetica, sans-serif; max-width: 600px; margin: 0 auto; color: #1a1a1a; line-height: 1.6;">

  <h1 style="font-size: 22px; color: #0d3b66; border-bottom: 3px solid #0d3b66; padding-bottom: 8px; margin-bottom: 16px;">
    Daily Market Brief — ${today}
  </h1>

  <p style="margin: 0 0 20px 0; background-color: #eef3f8; border-left: 4px solid #0d3b66; padding: 10px 14px; font-size: 14px;">
    <strong>TL;DR:</strong> [1-2 lines: the single biggest driver today + the channel's current (most-recent) market lean]
  </p>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Key Market Themes</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;">[theme] <span style="font-size: 12px; color: #555; font-weight: bold;">[Bullish/Bearish/Cautious/Neutral]</span></li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Today's Calendar &amp; Triggers</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;"><strong>[Absolute date]</strong> — [scheduled event, one line]</li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Stocks &amp; Sectors in Focus</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;"><strong>[Company name]</strong> <span style="font-size: 12px; color: #555; font-weight: bold;">[tag]</span> — [one line; fact vs expectation made clear]</li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Deep Dive: [topic]</h2>
  <p style="margin: 0 0 8px 0;">[2-3 line plain-language summary of the single-topic video — include the headline number]</p>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;"><strong>[Company]</strong> <span style="font-size: 12px; color: #555; font-weight: bold;">[tag]</span> — [up to ~4 concrete data points: m-cap, holdings, growth, pledge, etc.]</li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Analyst Calls &amp; Price Targets</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;"><strong>[Named institution]</strong> — [call / target]</li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Macro &amp; Global Cues</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;">[central banks, global cues, policy/trade news not already listed in Calendar]</li>
  </ul>

  <h2 style="font-size: 17px; color: #b3261e; margin-top: 24px; margin-bottom: 8px;">Risks &amp; Caveats</h2>
  <ul style="margin: 0; padding-left: 20px;">
    <li style="margin-bottom: 6px;">[downside risks + any fake-news / unconfirmed flags the channel raised]</li>
  </ul>

  <h2 style="font-size: 17px; color: #0d3b66; margin-top: 24px; margin-bottom: 8px;">Bottom Line</h2>
  <p style="margin: 0; background-color: #f0f4f8; padding: 12px 16px; border-radius: 6px;">
    [tight 3-sentence executive summary of today's setup]
  </p>

  <p style="margin-top: 28px; font-size: 12px; color: #888888; border-top: 1px solid #e0e0e0; padding-top: 10px;">
    Source: Stock Market का Commando (single YouTube channel) — auto-generated summary of the channel's own views and claims. Informational only; not investment advice. Verify before acting.
  </p>

</div>`;

const parts = [{
  text: `Below are the channel's videos from the last 24 hours, in chronological order (OLDEST first; the LAST video is the most recent and represents the channel's current stance). For each video, analyse the spoken Hindi audio AND the on-screen visuals — charts, tickers and figures shown on screen are often the most reliable source for company names and numbers.`,
}];

for (let i = 0; i < selected.length; i++) {
  const v = selected[i];
  parts.push({ text: `--- VIDEO ${i + 1} of ${selected.length} | TITLE: ${v.title} | PUBLISHED: ${v.publishedAt} ---` });
  parts.push({ fileData: { fileUri: v.url } });
}

const body = {
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts }],
  generationConfig: { temperature: 0.3 },
};

return [{ json: { body, videoCount: selected.length } }];
